from __future__ import annotations

import collections.abc as cabc
import textwrap
from contextlib import contextmanager


class TextWrapper(textwrap.TextWrapper):
    def _handle_long_word(
        self,
        reversed_chunks: list[str],
        cur_line: list[str],
        cur_len: int,
        width: int,
    ) -> None:
        """Handle a word that is longer than the allowed width.

        This modifies reversed_chunks and cur_line in-place according to the
        instance settings. If break_long_words is True, the word will be split
        to fit the remaining space on the current line (at least one character
        will be placed). If break_long_words is False and the current line is
        empty, the whole long word will be appended to the current line.
        """
        space_left = max(width - cur_len, 1)

        if self.break_long_words:
            last = reversed_chunks[-1]
            cut = last[:space_left]
            res = last[space_left:]
            cur_line.append(cut)
            reversed_chunks[-1] = res
        elif not cur_line:
            cur_line.append(reversed_chunks.pop())

    @contextmanager
    def extra_indent(self, indent: str) -> cabc.Iterator[None]:
        """Temporarily add extra indentation to the wrapper.

        The provided indent string is appended to both initial_indent and
        subsequent_indent for the duration of the context. The original
        indentation values are restored when exiting the context.

        Example:
            with wrapper.extra_indent('    '):
                # wrapper.initial_indent and wrapper.subsequent_indent have
                # the extra 4 spaces for the duration of the block
        """
        old_initial_indent = self.initial_indent
        old_subsequent_indent = self.subsequent_indent
        self.initial_indent += indent
        self.subsequent_indent += indent

        try:
            yield
        finally:
            self.initial_indent = old_initial_indent
            self.subsequent_indent = old_subsequent_indent

    def indent_only(self, text: str) -> str:
        """Apply the wrapper's indentation to each line without wrapping.

        The first line gets initial_indent and subsequent lines get
        subsequent_indent. The original line breaks in the input text are
        preserved.
        """
        rv = []

        for idx, line in enumerate(text.splitlines()):
            indent = self.initial_indent

            if idx > 0:
                indent = self.subsequent_indent

            rv.append(f"{indent}{line}")

        return "\n".join(rv)